class CountIntervals:
    def __init__(self):
        self.intervals = []
        self.counts = {}

    def add(self, left: int, right: int) -> None:
        self.intervals.append((left, right))
        for i in range(left, right + 1):
            self.counts[i] = self.counts.get(i, 0) + 1

    def count(self) -> int:
        return len(self.counts)
